{
  "mode": "method",
  "tests": [
    {
      "name": "get_project_members",
      "input": {
        "projectId": "123",
        "fields": "id,name,role"
      },
      "output": [
        {
          "id": "1",
          "name": "Alice",
          "role": "admin"
        },
        {
          "id": "2",
          "name": "Bob",
          "role": "member"
        }
      ],
      "notes": "Validates retrieval of project members with specific fields."
    },
    {
      "name": "add_project_member",
      "input": {
        "projectId": "123",
        "member": {
          "name": "Charlie",
          "role": "member"
        }
      },
      "output": {
        "id": "3",
        "name": "Charlie",
        "role": "member"
      },
      "notes": "Tests adding a new member to a project."
    },
    {
      "name": "get_invites",
      "input": {
        "projectId": "123",
        "fields": "id,email,status"
      },
      "output": [
        {
          "id": "1",
          "email": "invitee@example.com",
          "status": "pending"
        }
      ],
      "notes": "Validates retrieval of project invites with specific fields."
    },
    {
      "name": "accept_invite",
      "input": {
        "projectId": "123",
        "inviteId": "1"
      },
      "output": {
        "status": "accepted"
      },
      "notes": "Tests acceptance of an invite and checks status transition."
    },
    {
      "name": "delete_member",
      "input": {
        "projectId": "123",
        "memberId": "2"
      },
      "output": {
        "status": "deleted"
      },
      "notes": "Validates deletion of a member from a project."
    },
    {
      "name": "duplicate_invite",
      "input": {
        "projectId": "123",
        "invite": {
          "email": "invitee@example.com"
        }
      },
      "output": {
        "error": "Invite already exists"
      },
      "notes": "Tests handling of duplicate invites."
    },
    {
      "name": "primary_member_rule",
      "input": {
        "projectId": "123",
        "member": {
          "name": "David",
          "role": "customer"
        }
      },
      "output": {
        "error": "Only one primary customer allowed"
      },
      "notes": "Validates enforcement of primary member rules."
    },
    {
      "name": "invalid_project_id",
      "input": {
        "projectId": "999",
        "fields": "id,name,role"
      },
      "output": {
        "error": "Project not found"
      },
      "notes": "Tests response for invalid project ID."
    }
  ],
  "assumptions": "All endpoints are expected to follow legacy behavior closely.",
  "notes": "Ensure to test both valid and edge cases for robust validation."
}
